let preview=document.getElementById("previewImg"),modal=document.getElementById("modal"),modalImg=document.getElementById("modalImg");function getCurrentImage(){return{src:preview.src,title:document.getElementById("title").innerText||"poster"}}function openModal(){modal.style.display="flex",modalImg.src=preview.src}function closeModal(){modal.style.display="none"}async function downloadImg(e){e.innerText="Waiting...";const t=getCurrentImage();try{let s=await fetch(t.src+"?t="+Date.now()),o=await s.blob(),n=URL.createObjectURL(o),e=document.createElement("a");e.href=n,e.download=t.title+".gif",e.click(),URL.revokeObjectURL(n)}catch{alert("Download failed")}e.innerText="⬇️ Download"}async function shareImg(e){e.innerText="Sharing...";const t={src:document.getElementById("previewImg").src,title:document.getElementById("title").innerText||"image"};try{const e=await fetch(t.src+"?t="+Date.now());if(!e.ok)throw new Error("Fetch failed");const n=await e.blob(),s=new File([n],t.title+".gif",{type:n.type||"image/gif"});navigator.canShare&&navigator.canShare({files:[s]})?await navigator.share({title:t.title,files:[s]}):alert("❌ आपका device file share support नहीं करता")}catch(e){console.error("Share Error:",e),alert("❌ Sharing failed")}e.innerText="🔗 Share"}function printImg(e){e.innerText="Preparing...";const n=getCurrentImage(),t=window.open("");t.document.write(`
    <html>
    <body style="margin:0;text-align:center;">
      <img src="${n.src}" style="max-width:100%;">
      <script>
        window.onload=function(){
          window.print();
          setTimeout(()=>window.close(),500);
        }
      <\/script>
    </body>
    </html>
  `),t.document.close(),e.innerText="🖨️ Print"}function renderGallery(e){categoryContainer.innerHTML="";const t=[...new Set(e.map(e=>e.category))];t.forEach(t=>{const n=document.createElement("div");n.className="category",n.innerHTML=`<h2>${t}</h2><div class="gallery"></div>`;const s=n.querySelector(".gallery");e.filter(e=>e.category===t).forEach(e=>{const t=document.createElement("div");t.className="gallery-item";const o=document.createElement("div");o.className="skeleton";const n=document.createElement("img");n.loading="lazy",n.src=e.src,n.style.display="none",n.onload=()=>{o.remove(),n.style.display="block"},t.appendChild(o),t.appendChild(n);const i=document.createElement("div");i.className="image-title",i.innerText=e.title,t.appendChild(i),t.onclick=()=>openModal(e),s.appendChild(t)}),categoryContainer.appendChild(n)})}